import React from 'react';
import { client } from '../src/libs/client'; 
import Link from "next/link";

// 以下の「type Blog = ...」からは変更なし
// 1. microCMSからデータを取得する関数
async function getBlogPosts() {
  const data = await client.get({
    endpoint: "blog", // 修正済み: エンドポイントを 'blog' に指定
    queries: { limit: 3 }, // 最新の3件を取得
  });
  return data.contents;
}

export default async function Home() {
  const posts = await getBlogPosts();

  return (
    <main className="min-h-screen bg-slate-100"> {/* text-blue-100 から修正 */}
      
      {/* ヒーローセクション */}
      <section className="bg-[#0ABAB5] text-white py-20 px-4 text-center"> {/* bg-blue-400 から修正 */}
        <h1 className="text-4xl md:text-6xl font-bold mb-4">
          大阪のエアコン工事なら<br />aircon-osaka.jp
        </h1>
        <p className="text-xl">プロの技術で、快適な空間をお届けします。</p>
      </section>

      {/* お知らせ・ブログセクション */}
      <section className="max-w-5xl mx-auto py-16 px-4">
        <h2 className="text-3xl font-bold text-center mb-10 text-[#0ABAB5]"> {/* text-blue-600 から修正 */}
          Latest Blog
        </h2>
        
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          {posts.map((post: any) => (
            <Link key={post.id} href={`/blog/${post.id}`}>
              <article className="bg-white rounded-lg shadow-md overflow-hidden hover:border-[#0ABAB5] border-2 border-transparent transition-all"> {/* hover:border-blue-200 から修正 */}
                {post.eyecatch && (
                  <img 
                    src={post.eyecatch.url} 
                    alt={post.title} 
                    className="w-full h-48 object-cover"
                  />
                )}
                <div className="p-4">
                  <p className="text-sm text-gray-500 mb-2">
                    {new Date(post.publishedAt).toLocaleDateString('ja-JP')}
                  </p>
                  <h3 className="font-bold text-lg mb-2 text-slate-800">
                    {post.title}
                  </h3>
                  <p className="text-[#0ABAB5] text-sm font-semibold">詳しく見る →</p> {/* text-blue-500 から修正 */}
                </div>
              </article>
            </Link>
          ))}
        </div>
      </section>

      {/* サービス紹介バナー */}
      <section className="bg-[#0ABAB5]/10 py-16 px-4"> {/* bg-blue-50 から修正 */}
        <div className="max-w-4xl mx-auto text-center">
          <h2 className="text-2xl font-bold mb-6 text-slate-800">お問い合わせはこちら</h2>
          <button className="bg-[#0ABAB5] text-white px-8 py-3 rounded-full font-bold hover:opacity-90 transition-opacity">
            無料見積もり依頼
          </button>
        </div>
      </section>

    </main>
  );
}